from math import gcd

class Solution:
    def selfDivisiblePermutationCount(self, n: int) -> int:
        def backtrack(pos, used):
            if pos > n:
                return 1

            count = 0
            for num in range(1, n + 1):
                if not used[num] and gcd(num, pos) == 1:
                    used[num] = True
                    count += backtrack(pos + 1, used)
                    used[num] = False

            return count

        used = [False] * (n + 1)
        return backtrack(1, used)

